#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding ergonomic-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:text! \
    last_name:text! \
    date_of_birth:date! \
    sex:text! \
    occupation:text! \
    employer:text! \
    job_title:text! \
    years_in_role:int \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:text! \
    --htmx

cargo loco generate scaffold assessment_workstation_setup \
    assessment:references \
    desk_height:text! \
    chair_type:text! \
    chair_adjustability:text! \
    monitor_position:text! \
    monitor_distance:text! \
    monitor_height:text! \
    keyboard_placement:text! \
    mouse_placement:text! \
    lighting:text! \
    temperature:text! \
    --htmx

cargo loco generate scaffold assessment_posture \
    assessment:references \
    sitting_posture:text! \
    standing_posture:text! \
    neck_angle:text! \
    trunk_angle:text! \
    shoulder_position:text! \
    wrist_deviation:text! \
    neck_score:int \
    trunk_score:int \
    leg_score:int \
    upper_arm_score:int \
    lower_arm_score:int \
    wrist_score:int \
    --htmx

cargo loco generate scaffold assessment_repetitive_tasks \
    assessment:references \
    task_description:text! \
    frequency:text! \
    duration_per_session:text! \
    force_required:text! \
    vibration_exposure:text! \
    cycle_time_seconds:int \
    --htmx

cargo loco generate scaffold assessment_manual_handling \
    assessment:references \
    lifting_frequency:text! \
    load_weight_kg:double \
    carry_distance_metres:double \
    push_pull_forces:text! \
    team_lifting:text! \
    mechanical_aids_available:text! \
    --htmx

cargo loco generate scaffold assessment_current_symptoms \
    assessment:references \
    pain_locations:text! \
    pain_severity:int \
    onset_date:date \
    duration:text! \
    aggravating_factors:text! \
    relieving_factors:text! \
    impact_on_work:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    musculoskeletal_conditions:text! \
    previous_injuries:text! \
    surgeries:text! \
    chronic_pain:text! \
    rsi_carpal_tunnel:text! \
    back_problems:text! \
    --htmx

cargo loco generate scaffold assessment_current_interventions \
    assessment:references \
    ergonomic_equipment:text! \
    physiotherapy:text! \
    occupational_therapy:text! \
    workplace_adjustments:text! \
    medications:text! \
    --htmx

cargo loco generate scaffold assessment_psychosocial_factors \
    assessment:references \
    job_satisfaction:text! \
    workload:text! \
    stress_level:text! \
    breaks_taken:text! \
    autonomy:text! \
    employer_support:text! \
    --htmx

cargo loco generate scaffold assessment_recommendations \
    assessment:references \
    equipment_changes:text! \
    workstation_modifications:text! \
    training_required:text! \
    break_schedule:text! \
    follow_up_date:date \
    referrals:text! \
    --htmx

cargo loco generate scaffold reba_rule \
    system:text! \
    description:text! \
    score:int! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    reba_score:int! \
    risk_level:text! \
    reba_score_override:int \
    override_reason:text! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule:references \
    system:text! \
    description:text! \
    score:int! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
